"use strict";(()=>{async function s(o,t={}){let e=new Headers(t.headers);e.has("accept")||e.set("accept","application/json");let n=await fetch(o,{credentials:"same-origin",...t,headers:e});if(n.status===401)throw location.href="/app/login?next="+encodeURIComponent(location.pathname+location.search),new Error("session expired");return n}async function a(o,t){try{let e=await s("/app/tasks/complete",{method:"POST",headers:{"content-type":"application/json"},body:JSON.stringify({id:o})});if(!e.ok)throw new Error("complete "+e.status);let n=t.parentElement;t.remove(),n&&n.children.length===0&&(n.outerHTML='<p class="home-empty">Nada vencendo nas pr\xF3ximas 24h.</p>')}catch(e){console.warn("home: complete failed",e)}}function c(){document.querySelectorAll(".home-task-complete").forEach(o=>{o.addEventListener("click",()=>{let t=o.dataset.id,e=o.closest("li");t&&e&&a(t,e)})})}c();})();
